// Classify Issue & Create Ticket
// Auto-detects category and priority from the tenant's message

const text = ($json.text || '').toLowerCase().trim();
const phone = $json.waId || $json.from || 'unknown';
const tenantName = $json.senderName || 'Tenant';
const now = new Date();

const categories = {
  Plumbing:   ['leak', 'pipe', 'water', 'tap', 'drain', 'toilet', 'flush', 'sink', 'shower', 'sewage'],
  Electrical: ['light', 'power', 'electricity', 'switch', 'socket', 'outlet', 'fuse', 'wiring', 'fan', 'ac', 'air condition'],
  Appliance:  ['fridge', 'washing machine', 'oven', 'microwave', 'dishwasher', 'heater', 'geyser', 'appliance'],
  Security:   ['lock', 'door', 'window', 'cctv', 'camera', 'key', 'gate', 'security', 'break', 'stolen'],
  Structural: ['wall', 'ceiling', 'floor', 'crack', 'roof', 'paint', 'damp', 'mold', 'mould', 'termite'],
  Other:      []
};

let detectedCategory = 'Other';
for (const [cat, keywords] of Object.entries(categories)) {
  if (keywords.some(k => text.includes(k))) { detectedCategory = cat; break; }
}

const highPriorityWords = ['emergency', 'urgent', 'flood', 'fire', 'gas leak', 'no power', 'burst', 'danger', 'break-in'];
const lowPriorityWords  = ['minor', 'small', 'whenever', 'no rush', 'paint', 'cosmetic'];

let priority = 'Medium';
if (highPriorityWords.some(w => text.includes(w))) priority = 'High';
else if (lowPriorityWords.some(w => text.includes(w))) priority = 'Low';

const slaHours = { High: 4, Medium: 24, Low: 72 };
const slaDue = new Date(now.getTime() + slaHours[priority] * 60 * 60 * 1000);

const datePart = now.toISOString().split('T')[0].replace(/-/g, '');
const randPart = Math.random().toString(36).substring(2, 6).toUpperCase();
const ticketId = `TKT-${datePart}-${randPart}`;

const teamMap = {
  Plumbing:   { name: 'Plumbing Team',   phone: 917727827113 },
  Electrical: { name: 'Electrical Team', phone: '917024935915' },
  Appliance:  { name: 'Appliance Team',  phone: 'APPLIANCE_TEAM_PHONE' },
  Security:   { name: 'Security Team',   phone: 'SECURITY_TEAM_PHONE' },
  Structural: { name: 'Structural Team', phone: 'STRUCTURAL_TEAM_PHONE' },
  Other:      { name: 'General Team',    phone: 'GENERAL_TEAM_PHONE' }
};

const assignedTeam = teamMap[detectedCategory];
const priorityEmoji = { High: '\u{1F534}', Medium: '\u{1F7E1}', Low: '\u{1F7E2}' }[priority];

const tenantMsg = [
  `\uD83C\uDFAB *Ticket Created Successfully!*`,
  '',
  `\uD83D\uDCCB *Ticket ID:* \`${ticketId}\``,
  `\uD83C\uDFF7\uFE0F *Category:* ${detectedCategory}`,
  `${priorityEmoji} *Priority:* ${priority}`,
  `\uD83D\uDCDD *Issue:* ${$json.text}`,
  `\uD83D\uDD50 *Logged At:* ${now.toLocaleString('en-IN')}`,
  `\u23F0 *Expected Resolution:* Within ${slaHours[priority]} hours`,
  '',
  'Our team has been notified and will be in touch shortly.',
  `Save your Ticket ID *${ticketId}* for future reference.`,
  '',
  'Reply *mystatus* anytime to check your open tickets.'
].join('\n');

const teamMsg = [
  `\uD83D\uDD14 *New Maintenance Ticket*`,
  '',
  `\uD83C\uDFAB *Ticket ID:* ${ticketId}`,
  `${priorityEmoji} *Priority:* ${priority}`,
  `\uD83C\uDFF7\uFE0F *Category:* ${detectedCategory}`,
  `\uD83D\uDC64 *Tenant:* ${tenantName}`,
  `\uD83D\uDCDE *Phone:* ${phone}`,
  `\uD83D\uDCDD *Issue:* ${$json.text}`,
  `\u23F0 *SLA Deadline:* ${slaDue.toLocaleString('en-IN')}`,
  '',
  'To update status, reply:',
  `*update ${ticketId} in-progress Your note here*`
].join('\n');

return { json: {
  ticketId, phone, tenantName,
  issueText: $json.text,
  category: detectedCategory,
  priority,
  status: 'Open',
  assignedTeam: assignedTeam.name,
  teamPhone: assignedTeam.phone,
  createdAt: now.toISOString(),
  slaDueAt: slaDue.toISOString(),
  rating: '',
  tenantMsg,
  teamMsg
}};

// Parse Status Update from Maintenance Team
// Format: 'update TKT-20240225-ABCD in-progress Technician arriving at 3PM'

const text = ($('Wati Trigger').item.json.text || '').trim();
const updaterPhone = $('Wati Trigger').item.json.waId || $('Wati Trigger').item.json.from;

const parts = text.replace(/^update\s+/i, '').split(' ');
const ticketId = (parts[0] || '').toUpperCase();
const newStatus = (parts[1] || '').toLowerCase();
const note = parts.slice(2).join(' ') || '';

const validStatuses = ['assigned', 'in-progress', 'resolved', 'closed'];
if (!ticketId || !validStatuses.includes(newStatus)) {
  return [{ json: {
    updaterPhone,
    errorMessage: `\u26A0\uFE0F Invalid format. Use:\n*update <TICKET-ID> <status> <note>*\n\nValid statuses: ${validStatuses.join(', ')}\n\nExample:\n*update TKT-20240225-ABCD in-progress Technician on the way*`,
    hasError: true
  }}];
}

const allRows = $input.all();
const ticketRow = allRows.find(r => (r.json.ticketId || '').toUpperCase() === ticketId);

if (!ticketRow) {
  return [{ json: {
    updaterPhone,
    errorMessage: `\u274C Ticket *${ticketId}* not found. Please check the ticket ID.`,
    hasError: true
  }}];
}

const ticket = ticketRow.json;
const now = new Date();
const priorityEmoji = { High: '\uD83D\uDD34', Medium: '\uD83D\uDFE1', Low: '\uD83D\uDFE2' }[ticket.priority] || '\u26AA';
const statusEmoji   = { assigned: '\uD83D\uDC77', 'in-progress': '\uD83D\uDD27', resolved: '\u2705', closed: '\uD83D\uDD12' }[newStatus] || '\uD83D\uDCCB';

const ackMessage = [
  `${statusEmoji} *Ticket Updated*`,
  `\uD83C\uDFAB ${ticketId} \u2192 *${newStatus.toUpperCase()}*`,
  note ? `\uD83D\uDCDD Note: ${note}` : '',
  `\uD83D\uDD50 Updated at ${now.toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit'})}`
].filter(Boolean).join('\n');

const tenantLines = [
  `${statusEmoji} *Ticket Update \u2013 ${ticketId}*`,
  '',
  'Your maintenance request has been updated:',
  '',
  `\uD83D\uDCCB *Status:* ${newStatus.toUpperCase()}`,
  `\uD83C\uDFF7\uFE0F *Category:* ${ticket.category}`,
  `${priorityEmoji} *Priority:* ${ticket.priority}`,
  note ? `\uD83D\uDCDD *Note from team:* ${note}` : '',
  `\uD83D\uDD50 *Updated:* ${now.toLocaleString('en-IN')}`
].filter(Boolean);

if (newStatus === 'resolved') {
  tenantLines.push('');
  tenantLines.push('\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501');
  tenantLines.push('\u2B50 *How did we do?*');
  tenantLines.push(`Reply: *rate ${ticketId} <1-5>*`);
  tenantLines.push(`Example: *rate ${ticketId} 5*`);
} else {
  tenantLines.push('');
  tenantLines.push('Reply *mystatus* to see all your tickets.');
}

return [{ json: {
  ticketId,
  tenantPhone: ticket.phone,
  updaterPhone,
  newStatus, note,
  updatedAt: now.toISOString(),
  ackMessage,
  tenantMessage: tenantLines.join('\n'),
  isResolved: newStatus === 'resolved',
  hasError: false
}}];

// Parse & Log Rating
// Format: 'rate TKT-20240225-ABCD 5'

const text = ($('Wati Trigger').item.json.text || '').trim();
const phone = $('Wati Trigger').item.json.waId || $('Wati Trigger').item.json.from;
const tenantName = $('Wati Trigger').item.json.senderName || 'Tenant';

const parts = text.replace(/^rate\s+/i, '').split(' ');
const ticketId = (parts[0] || '').toUpperCase();
const rating   = parseInt(parts[1] || '0');

if (!ticketId || isNaN(rating) || rating < 1 || rating > 5) {
  return [{ json: {
    phone,
    ratingMessage: `\u26A0\uFE0F Invalid format. Use:\n*rate <TICKET-ID> <1-5>*\n\nExample: *rate TKT-20240225-ABCD 5*`,
    hasError: true
  }}];
}

const stars = '\u2B50'.repeat(rating) + '\u2606'.repeat(5 - rating);
const feedbackMap = { 5: 'Excellent!', 4: 'Good!', 3: 'Average', 2: 'Below expectations', 1: 'Poor \u2013 we will improve' };

const ratingLines = [
  `${stars} *Thank you for your feedback!*`,
  '',
  `You rated ticket *${ticketId}*: *${rating}/5 \u2013 ${feedbackMap[rating]}*`,
  '',
  'Your feedback helps us improve our service.',
  'For any new issues, just send us a message! \uD83C\uDFE0'
];

return [{ json: {
  phone, ticketId, rating,
  ratingMessage: ratingLines.join('\n'),
  ratedAt: new Date().toISOString(),
  hasError: false
}}];

// Build My Tickets Status Card

const phone = $('Wati Trigger').item.json.waId || $('Wati Trigger').item.json.from;
const tenantName = $('Wati Trigger').item.json.senderName || 'Tenant';
const allRows = $input.all();

const myTickets = allRows
  .filter(r => r.json.phone === phone)
  .sort((a, b) => new Date(b.json.createdAt) - new Date(a.json.createdAt));

if (myTickets.length === 0) {
  return [{ json: {
    phone,
    myTicketsMessage: `\uD83D\uDCCB *No tickets found, ${tenantName}!*\n\nTo report a maintenance issue, just describe your problem in a message.\nExample: *The kitchen tap is leaking*`
  }}];
}

const open   = myTickets.filter(r => !['resolved','closed'].includes((r.json.status||'').toLowerCase()));
const closed = myTickets.filter(r =>  ['resolved','closed'].includes((r.json.status||'').toLowerCase())).slice(0, 3);

const statusEmoji = { open: '\uD83D\uDFE0', assigned: '\uD83D\uDC77', 'in-progress': '\uD83D\uDD27', resolved: '\u2705', closed: '\uD83D\uDD12' };
const priorityEmoji = { High: '\uD83D\uDD34', Medium: '\uD83D\uDFE1', Low: '\uD83D\uDFE2' };

const lines = [`\uD83D\uDCCB *My Maintenance Tickets*`, `\uD83D\uDC64 *${tenantName}*`, ''];

if (open.length > 0) {
  lines.push(`*Open Tickets (${open.length}):*`);
  for (const r of open) {
    const se = statusEmoji[(r.json.status||'open').toLowerCase()] || '\uD83D\uDCCB';
    const pe = priorityEmoji[r.json.priority] || '\u26AA';
    let created = r.json.createdAt;
    try { created = new Date(r.json.createdAt).toLocaleDateString('en-IN', { day:'numeric', month:'short' }); } catch(e) {}
    lines.push(`${se} *${r.json.ticketId}* ${pe} ${r.json.priority}`);
    lines.push(`   ${r.json.category} | ${r.json.status || 'Open'}`);
    lines.push(`   \uD83D\uDCC5 Raised: ${created}`);
    if (r.json.notes) lines.push(`   \uD83D\uDCDD ${r.json.notes}`);
    lines.push('');
  }
}

if (closed.length > 0) {
  lines.push(`*Recently Closed (${closed.length}):*`);
  for (const r of closed) {
    const rating = r.json.rating ? `\u2B50 ${r.json.rating}/5` : 'Not rated';
    lines.push(`\u2705 ${r.json.ticketId} \u2013 ${r.json.category} | ${rating}`);
  }
  lines.push('');
}

lines.push('\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501');
lines.push('To report a new issue, just describe it in a message.');

return [{ json: { phone, myTicketsMessage: lines.join('\n') } }];

// Build Landlord Dashboard

const allRows = $input.all();
const now = new Date();
const requesterPhone = $('Wati Trigger').item.json.waId || $('Wati Trigger').item.json.from;

const allTickets = allRows.map(r => r.json);
const openTickets = allTickets.filter(t => !['resolved','closed'].includes((t.status||'').toLowerCase()));
const resolvedTickets = allTickets.filter(t => ['resolved','closed'].includes((t.status||'').toLowerCase()));

const breached = openTickets.filter(t => { const due = new Date(t.slaDueAt || 0); return due < now; });

const catCount = {};
for (const t of openTickets) { const c = t.category || 'Other'; catCount[c] = (catCount[c] || 0) + 1; }

const rated = allTickets.filter(t => t.rating && parseFloat(t.rating) > 0);
const avgRating = rated.length > 0 ? (rated.reduce((s, t) => s + parseFloat(t.rating), 0) / rated.length).toFixed(1) : 'N/A';

const highOpen = openTickets.filter(t => t.priority === 'High').length;
const medOpen  = openTickets.filter(t => t.priority === 'Medium').length;
const lowOpen  = openTickets.filter(t => t.priority === 'Low').length;

const recent5 = openTickets.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)).slice(0, 5);

const lines = [
  `\uD83C\uDFE0 *Property Management Dashboard*`,
  `\uD83D\uDCC5 ${now.toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long' })}`,
  '',
  `\u2501\u2501 *Ticket Overview* \u2501\u2501`,
  `\uD83D\uDCC2 Total Open:     *${openTickets.length}*`,
  `\u2705 Resolved:       *${resolvedTickets.length}*`,
  `\uD83D\uDEA8 SLA Breaches:   *${breached.length}*`,
  `\u2B50 Avg Rating:     *${avgRating}/5*`,
  '',
  `\u2501\u2501 *By Priority* \u2501\u2501`,
  `\uD83D\uDD34 High: ${highOpen}  |  \uD83D\uDFE1 Medium: ${medOpen}  |  \uD83D\uDFE2 Low: ${lowOpen}`,
  '',
  `\u2501\u2501 *By Category* \u2501\u2501`,
  ...Object.entries(catCount).map(([c, n]) => `  ${c}: ${n}`)
];

if (breached.length > 0) {
  lines.push('');
  lines.push(`\u2501\u2501 \uD83D\uDEA8 *SLA Breaches* \u2501\u2501`);
  for (const t of breached.slice(0, 5)) {
    const pe = { High: '\uD83D\uDD34', Medium: '\uD83D\uDFE1', Low: '\uD83D\uDFE2' }[t.priority] || '\u26AA';
    lines.push(`${pe} *${t.ticketId}* \u2013 ${t.category}`);
    lines.push(`   Tenant: ${t.tenantName} | Status: ${t.status}`);
  }
}

if (recent5.length > 0) {
  lines.push('');
  lines.push('\u2501\u2501 *Recent Open Tickets* \u2501\u2501');
  for (const t of recent5) {
    const pe = { High: '\uD83D\uDD34', Medium: '\uD83D\uDFE1', Low: '\uD83D\uDFE2' }[t.priority] || '\u26AA';
    let created = t.createdAt;
    try { created = new Date(t.createdAt).toLocaleDateString('en-IN', { day:'numeric', month:'short' }); } catch(e) {}
    lines.push(`${pe} *${t.ticketId}* \u2013 ${t.category} (${t.status})`);
    lines.push(`   ${t.tenantName} | ${created}`);
  }
}

return [{ json: { phone: requesterPhone, dashboardMessage: lines.join('\n') } }];

// Daily SLA Breach Check
const allRows = $input.all();
const now = new Date();

const openTickets = allRows.map(r => r.json).filter(t => !['resolved','closed'].includes((t.status||'').toLowerCase()));

if (openTickets.length === 0) {
  return [{ json: { message: 'No open tickets \u2013 all clear!', hasBreaches: false } }];
}

const breached = [];
const dueSoon  = [];
const onTrack  = [];

for (const t of openTickets) {
  const due = new Date(t.slaDueAt || 0);
  const hoursLeft = (due - now) / (1000 * 60 * 60);
  if (hoursLeft < 0)       breached.push({ ...t, hoursOverdue: Math.abs(hoursLeft).toFixed(1) });
  else if (hoursLeft <= 4) dueSoon.push({ ...t, hoursLeft: hoursLeft.toFixed(1) });
  else                     onTrack.push(t);
}

const pe = { High: '\uD83D\uDD34', Medium: '\uD83D\uDFE1', Low: '\uD83D\uDFE2' };

const landlordLines = [
  `\uD83D\uDCCA *Daily SLA Report \u2013 ${now.toLocaleDateString('en-IN')}*`,
  '',
  `\uD83D\uDCC2 Open: ${openTickets.length} | \uD83D\uDEA8 Breached: ${breached.length} | \u26A0\uFE0F Due Soon: ${dueSoon.length} | \u2705 On Track: ${onTrack.length}`,
  ''
];

if (breached.length > 0) {
  landlordLines.push('\uD83D\uDEA8 *SLA BREACHED \u2013 Immediate Action Required:*');
  for (const t of breached) {
    landlordLines.push(`${pe[t.priority]||'\u26AA'} *${t.ticketId}* \u2013 ${t.category} (${t.hoursOverdue}h overdue)`);
    landlordLines.push(`   \uD83D\uDC64 ${t.tenantName} | Team: ${t.assignedTeam} | Status: ${t.status}`);
  }
  landlordLines.push('');
}

if (dueSoon.length > 0) {
  landlordLines.push('\u26A0\uFE0F *Due Within 4 Hours:*');
  for (const t of dueSoon) {
    landlordLines.push(`${pe[t.priority]||'\u26AA'} *${t.ticketId}* \u2013 ${t.category} (${t.hoursLeft}h left)`);
    landlordLines.push(`   \uD83D\uDC64 ${t.tenantName} | Team: ${t.assignedTeam}`);
  }
}

const teamAlerts = breached.map(t => ({
  teamPhone: t.teamPhone,
  teamMessage: [
    `\uD83D\uDEA8 *SLA BREACH ALERT*`,
    `\uD83C\uDFAB Ticket *${t.ticketId}* is *${t.hoursOverdue} hours overdue!*`,
    `\uD83C\uDFF7\uFE0F ${t.category} | ${pe[t.priority]||'\u26AA'} ${t.priority}`,
    `\uD83D\uDC64 Tenant: ${t.tenantName} (${t.phone})`,
    `\uD83D\uDCDD Issue: ${t.issueText}`,
    '',
    'Please resolve or update immediately!',
    `*update ${t.ticketId} in-progress <your note>*`
  ].join('\n')
}));

return [{ json: {
  landlordPhone: 'LANDLORD_WHATSAPP_NUMBER',
  landlordReport: landlordLines.join('\n'),
  teamAlerts,
  hasBreaches: breached.length > 0
}}];

// Send breach alerts to each maintenance team
const alerts = $('Check SLA Breaches').item.json.teamAlerts || [];
if (alerts.length === 0) return [{ json: { message: 'No team alerts to send' } }];
return alerts.map(a => ({ json: a }));
